/**
 * ✨ Dr. Spark — PhD in Developer Experience & UX Tooling (TypeScript)
 * Generated by Sovereign Forge.
 */
class SparkPersona(projectRoot: String? = null) : BaseActivePersona(projectRoot) {
    init {
        this.name = "Spark"
        this.emoji = "✨"
        this.role = "PhD Developer Experience Engineer"
        this.phd_identity = "Developer Experience & UX Tooling (TypeScript)"
        this.stack = "Kotlin"
        this.healingPrompt = ""
    }

    override suspend fun execute(context: ProjectContext): List<Any> {
        this.setContext(context)
        return this.performAudit()
    }

    override fun getAuditRules(): Map<String, Any> {
        return mapOf(
            "extensions" to listOf([".kt"]),
            "rules" to listOf<AuditRule>(
                // [
          {
                    "regex": "process\\.exit\\(\\d+\\)(?![\\s\\S]{0,30}console|log|error)",
                    "issue": "Saída Silenciosa: process.exit() sem aviso ao dev. Forneça contexto visível PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "throw\\s+new\\s+Error\\([\"'][\"']\\)",
                    "issue": "Erro Mudo: Error lançado com mensagem vazia PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "\\.on\\([\"']error[\"']\\s*,\\s*\\(\\)\\s*=>\\s*\\{\\s*\\}\\)",
                    "issue": "Erro Invisível: Event handler de erro vazio (engolido) PhD.",
                    "severity": "high"
          }
]
            )
        )
    }

    fun performAudit() {
        println("☕ [${name}] Starting fleet-wide audit via Hub PhD...")
    }

    fun reasonAboutObjective(objective: String, file: String, context: String) {
        println("☕ [${name}] Delegating reasoning for '${objective}' to Hub...")
    }

    fun delegateHealingToHub(file: String, issue: String) {
        println("☕ [${name}] Delegating healing for '$issue' to Hub...")
    }
}
